Simply logging failed logins without alerting mechanisms is a critical security gap. In the 2023 Microsoft Storm-0558 attack, lack of automated alerting allowed attackers to maintain access for over a month. Here's what many developers do wrong and how to fix it:

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const app = express();

app.use(express.json());

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.findUser(username);

    if (!user) {
      // Just logging to console - no alerting
      console.log(`Failed login attempt for user: ${username}`);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      // Logging without any threshold detection or alerting
      console.log(`Wrong password for user: ${username}`);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Successful login - also just console log
    console.log(`User ${username} logged in`);
    const token = generateToken(user);
    res.json({ token });

  } catch (error) {
    console.error('Login error:', error);
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Attack Scenario**:
```text
# Attacker performs credential stuffing attack
# 10,000 login attempts over 2 hours from distributed IPs
# Each failed attempt just logs to console
# No one notices until breach is discovered weeks later
```

**Why This Is Dangerous**:
- Console logs are ephemeral and often not monitored in production
- No threshold detection for brute force attacks
- No alerting mechanism to notify security teams
- No correlation of failed attempts across users or IPs
- Attackers can try thousands of passwords undetected

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const winston = require('winston');
const Redis = require('ioredis');
const nodemailer = require('nodemailer');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);

// Structured logging with Winston
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security.log' }),
    new winston.transports.Console()
  ]
});

// Alert thresholds
const ALERT_THRESHOLDS = {
  failedLoginsPerUser: 5,
  failedLoginsPerIP: 10,
  failedLoginsGlobal: 100,
  timeWindowSeconds: 300 // 5 minutes
};

async function checkAndAlert(username, ip) {
  const userKey = `failed:user:${username}`;
  const ipKey = `failed:ip:${ip}`;
  const globalKey = 'failed:global';

  // Increment counters with TTL
  const multi = redis.multi();
  multi.incr(userKey);
  multi.expire(userKey, ALERT_THRESHOLDS.timeWindowSeconds);
  multi.incr(ipKey);
  multi.expire(ipKey, ALERT_THRESHOLDS.timeWindowSeconds);
  multi.incr(globalKey);
  multi.expire(globalKey, ALERT_THRESHOLDS.timeWindowSeconds);

  const results = await multi.exec();
  const userCount = results[0][1];
  const ipCount = results[2][1];
  const globalCount = results[4][1];

  // Check thresholds and alert
  if (userCount === ALERT_THRESHOLDS.failedLoginsPerUser) {
    await sendSecurityAlert('USER_BRUTEFORCE', {
      username,
      attempts: userCount,
      ip,
      severity: 'HIGH'
    });
  }

  if (ipCount === ALERT_THRESHOLDS.failedLoginsPerIP) {
    await sendSecurityAlert('IP_BRUTEFORCE', {
      ip,
      attempts: ipCount,
      severity: 'HIGH'
    });
  }

  if (globalCount === ALERT_THRESHOLDS.failedLoginsGlobal) {
    await sendSecurityAlert('CREDENTIAL_STUFFING', {
      globalAttempts: globalCount,
      severity: 'CRITICAL'
    });
  }

  return { userCount, ipCount, globalCount };
}

async function sendSecurityAlert(alertType, details) {
  // Log the alert
  logger.warn('SECURITY_ALERT', {
    alertType,
    ...details,
    timestamp: new Date().toISOString()
  });

  // Send to SIEM/monitoring system
  // In production, integrate with PagerDuty, Slack, etc.
  await notifySecurityTeam(alertType, details);
}

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const clientIP = req.ip || req.connection.remoteAddress;

  try {
    const user = await db.findUser(username);

    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      // Log failed attempt with full context
      logger.info('LOGIN_FAILED', {
        username: username.substring(0, 50),
        ip: clientIP,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString(),
        reason: user ? 'invalid_password' : 'user_not_found'
      });

      // Check thresholds and trigger alerts
      await checkAndAlert(username, clientIP);

      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Log successful login
    logger.info('LOGIN_SUCCESS', {
      userId: user.id,
      username,
      ip: clientIP,
      timestamp: new Date().toISOString()
    });

    // Clear failed attempt counters on success
    await redis.del(`failed:user:${username}`);

    const token = generateToken(user);
    res.json({ token });

  } catch (error) {
    logger.error('LOGIN_ERROR', { error: error.message, stack: error.stack });
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Threshold-based alerting**: Automatically detects brute force patterns and triggers alerts when thresholds are exceeded
- **Multi-dimensional tracking**: Monitors failed attempts per user, per IP, and globally to catch different attack patterns
- **Structured logging**: JSON format logs with full context enable SIEM integration and forensic analysis
- **Time-windowed counters**: Redis-based counters with TTL prevent false positives from legitimate users over long periods

Excellent question! Sophisticated attackers use distributed IPs, slow attack rates, and timing tricks to evade simple threshold detection. In the Storm-0558 attack, attackers used forged tokens over weeks to avoid detection. Here's a production-grade detection and alerting system:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const winston = require('winston');
const Redis = require('ioredis');
const { WebClient } = require('@slack/web-api');
const axios = require('axios');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);
const slack = new WebClient(process.env.SLACK_BOT_TOKEN);

// Production logger with multiple transports
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'auth-service', environment: process.env.NODE_ENV },
  transports: [
    new winston.transports.File({ 
      filename: '/var/log/app/security.log',
      maxsize: 100 * 1024 * 1024, // 100MB
      maxFiles: 30,
      tailable: true
    }),
    // Send critical alerts directly to monitoring
    new winston.transports.Http({
      host: 'logs.example.com',
      port: 443,
      ssl: true,
      level: 'warn'
    })
  ]
});

// Behavioral analysis configuration
const DETECTION_CONFIG = {
  // Immediate alerts
  immediate: {
    failedLoginsPerUser: 5,
    failedLoginsPerIP: 15,
    timeWindowSeconds: 300
  },
  // Slow attack detection (credential stuffing)
  slowAttack: {
    uniqueUsersFromIP: 20,
    timeWindowHours: 1
  },
  // Anomaly detection
  anomaly: {
    globalBaselineMultiplier: 3,
    geoVelocityKmPerHour: 800, // Faster than commercial flight
    unusualHourThreshold: 0.1 // 10% of normal traffic
  },
  // Alert cooldown to prevent spam
  alertCooldownMinutes: 15
};

class SecurityAlertSystem {
  constructor() {
    this.alertChannels = {
      slack: process.env.SLACK_SECURITY_CHANNEL,
      pagerduty: process.env.PAGERDUTY_ROUTING_KEY,
      webhook: process.env.SIEM_WEBHOOK_URL
    };
  }

  async trackLoginAttempt(event) {
    const { username, ip, success, userAgent, timestamp } = event;

    // Store detailed event for analysis
    const eventId = crypto.randomUUID();
    const eventData = JSON.stringify({
      eventId,
      username: this.hashUsername(username),
      ip,
      success,
      userAgentHash: this.hashUserAgent(userAgent),
      timestamp,
      hour: new Date(timestamp).getHours()
    });

    // Add to time-series for analysis
    await redis.zadd('login:events', Date.now(), eventData);
    await redis.expire('login:events', 86400); // 24 hour retention

    if (!success) {
      await this.analyzeFailedAttempt(event);
    } else {
      await this.checkSuccessfulLoginAnomalies(event);
    }
  }

  async analyzeFailedAttempt(event) {
    const { username, ip, userAgent, timestamp } = event;
    const alerts = [];

    // 1. Immediate threshold checks
    const userFailures = await this.incrementCounter(`failed:user:${username}`, 
      DETECTION_CONFIG.immediate.timeWindowSeconds);
    const ipFailures = await this.incrementCounter(`failed:ip:${ip}`, 
      DETECTION_CONFIG.immediate.timeWindowSeconds);

    if (userFailures >= DETECTION_CONFIG.immediate.failedLoginsPerUser) {
      alerts.push({
        type: 'BRUTE_FORCE_USER',
        severity: 'HIGH',
        details: { username, attempts: userFailures, ip }
      });
    }

    if (ipFailures >= DETECTION_CONFIG.immediate.failedLoginsPerIP) {
      alerts.push({
        type: 'BRUTE_FORCE_IP',
        severity: 'HIGH',
        details: { ip, attempts: ipFailures }
      });
    }

    // 2. Credential stuffing detection (many users from one IP)
    await redis.sadd(`ip:users:${ip}`, username);
    await redis.expire(`ip:users:${ip}`, DETECTION_CONFIG.slowAttack.timeWindowHours * 3600);
    const uniqueUsers = await redis.scard(`ip:users:${ip}`);

    if (uniqueUsers >= DETECTION_CONFIG.slowAttack.uniqueUsersFromIP) {
      alerts.push({
        type: 'CREDENTIAL_STUFFING',
        severity: 'CRITICAL',
        details: { ip, uniqueUsers, timeWindow: '1 hour' }
      });
    }

    // 3. Distributed attack detection (many IPs targeting one user)
    await redis.sadd(`user:ips:${username}`, ip);
    await redis.expire(`user:ips:${username}`, 3600);
    const uniqueIPs = await redis.scard(`user:ips:${username}`);

    if (uniqueIPs >= 10 && userFailures >= 3) {
      alerts.push({
        type: 'DISTRIBUTED_ATTACK',
        severity: 'CRITICAL',
        details: { username, uniqueIPs, totalAttempts: userFailures }
      });
    }

    // 4. Global anomaly detection
    await this.checkGlobalAnomaly(alerts);

    // Send all triggered alerts
    for (const alert of alerts) {
      await this.sendAlert(alert);
    }
  }

  async checkSuccessfulLoginAnomalies(event) {
    const { username, ip, userAgent, timestamp } = event;

    // Get last login location
    const lastLogin = await redis.hgetall(`user:lastlogin:${username}`);

    if (lastLogin.ip && lastLogin.ip !== ip) {
      // Check for impossible travel
      const lastGeo = await this.getGeoLocation(lastLogin.ip);
      const currentGeo = await this.getGeoLocation(ip);

      if (lastGeo && currentGeo) {
        const distance = this.calculateDistance(lastGeo, currentGeo);
        const timeDiff = (Date.now() - parseInt(lastLogin.timestamp)) / 3600000; // hours
        const velocity = distance / timeDiff;

        if (velocity > DETECTION_CONFIG.anomaly.geoVelocityKmPerHour) {
          await this.sendAlert({
            type: 'IMPOSSIBLE_TRAVEL',
            severity: 'HIGH',
            details: {
              username,
              previousIP: lastLogin.ip,
              currentIP: ip,
              distanceKm: Math.round(distance),
              timeHours: timeDiff.toFixed(2),
              velocityKmH: Math.round(velocity)
            }
          });
        }
      }
    }

    // Update last login
    await redis.hmset(`user:lastlogin:${username}`, {
      ip,
      timestamp: Date.now(),
      userAgent
    });
    await redis.expire(`user:lastlogin:${username}`, 30 * 86400); // 30 days
  }

  async checkGlobalAnomaly(alerts) {
    const currentHour = new Date().getHours();
    const currentCount = await redis.get('failed:global:current') || 0;
    const baselineKey = `baseline:hour:${currentHour}`;
    const baseline = await redis.get(baselineKey) || 50; // Default baseline

    if (currentCount > baseline * DETECTION_CONFIG.anomaly.globalBaselineMultiplier) {
      alerts.push({
        type: 'GLOBAL_ANOMALY',
        severity: 'CRITICAL',
        details: {
          currentFailures: currentCount,
          baseline,
          multiplier: (currentCount / baseline).toFixed(2)
        }
      });
    }
  }

  async sendAlert(alert) {
    const cooldownKey = `alert:cooldown:${alert.type}:${JSON.stringify(alert.details).substring(0, 100)}`;
    const inCooldown = await redis.get(cooldownKey);

    if (inCooldown) {
      logger.debug('Alert suppressed due to cooldown', { alert });
      return;
    }

    // Set cooldown
    await redis.setex(cooldownKey, DETECTION_CONFIG.alertCooldownMinutes * 60, '1');

    // Log the alert
    logger.warn('SECURITY_ALERT', alert);

    // Send to Slack
    await this.sendSlackAlert(alert);

    // Send to SIEM webhook
    await this.sendToSIEM(alert);

    // For critical alerts, trigger PagerDuty
    if (alert.severity === 'CRITICAL') {
      await this.triggerPagerDuty(alert);
    }
  }

  async sendSlackAlert(alert) {
    try {
      const color = alert.severity === 'CRITICAL' ? '#FF0000' : '#FFA500';

      await slack.chat.postMessage({
        channel: this.alertChannels.slack,
        attachments: [{
          color,
          title: `🚨 Security Alert: ${alert.type}`,
          fields: [
            { title: 'Severity', value: alert.severity, short: true },
            { title: 'Time', value: new Date().toISOString(), short: true },
            ...Object.entries(alert.details).map(([key, value]) => ({
              title: key,
              value: String(value),
              short: true
            }))
          ],
          footer: 'Security Monitoring System'
        }]
      });
    } catch (error) {
      logger.error('Failed to send Slack alert', { error: error.message });
    }
  }

  async sendToSIEM(alert) {
    try {
      await axios.post(this.alertChannels.webhook, {
        timestamp: new Date().toISOString(),
        source: 'auth-service',
        ...alert
      }, {
        timeout: 5000,
        headers: { 'Authorization': `Bearer ${process.env.SIEM_API_KEY}` }
      });
    } catch (error) {
      logger.error('Failed to send SIEM alert', { error: error.message });
    }
  }

  async triggerPagerDuty(alert) {
    try {
      await axios.post('https://events.pagerduty.com/v2/enqueue', {
        routing_key: this.alertChannels.pagerduty,
        event_action: 'trigger',
        payload: {
          summary: `${alert.type}: ${JSON.stringify(alert.details)}`,
          severity: alert.severity.toLowerCase(),
          source: 'auth-service',
          custom_details: alert.details
        }
      });
    } catch (error) {
      logger.error('Failed to trigger PagerDuty', { error: error.message });
    }
  }

  async incrementCounter(key, ttl) {
    const count = await redis.incr(key);
    await redis.expire(key, ttl);
    return count;
  }

  hashUsername(username) {
    return crypto.createHash('sha256').update(username).digest('hex').substring(0, 16);
  }

  hashUserAgent(userAgent) {
    return crypto.createHash('sha256').update(userAgent || '').digest('hex').substring(0, 8);
  }

  async getGeoLocation(ip) {
    // Use IP geolocation service
    try {
      const response = await axios.get(`https://ipapi.co/${ip}/json/`, { timeout: 2000 });
      return { lat: response.data.latitude, lon: response.data.longitude };
    } catch {
      return null;
    }
  }

  calculateDistance(geo1, geo2) {
    // Haversine formula
    const R = 6371; // Earth's radius in km
    const dLat = (geo2.lat - geo1.lat) * Math.PI / 180;
    const dLon = (geo2.lon - geo1.lon) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(geo1.lat * Math.PI / 180) * Math.cos(geo2.lat * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  }
}

const alertSystem = new SecurityAlertSystem();

// Login endpoint with full monitoring
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const clientIP = req.headers['x-forwarded-for']?.split(',')[0] || req.ip;
  const userAgent = req.get('User-Agent');
  const timestamp = new Date().toISOString();

  try {
    const user = await db.findUser(username);
    const validPassword = user && await bcrypt.compare(password, user.passwordHash);

    // Track all attempts
    await alertSystem.trackLoginAttempt({
      username,
      ip: clientIP,
      userAgent,
      timestamp,
      success: !!validPassword
    });

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = generateToken(user);
    res.json({ token });

  } catch (error) {
    logger.error('LOGIN_ERROR', { 
      error: error.message, 
      username, 
      ip: clientIP 
    });
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Immediate Threshold Detection**:
```javascript
// Catches fast brute force attacks
if (userFailures >= 5) triggerAlert('BRUTE_FORCE_USER');
if (ipFailures >= 15) triggerAlert('BRUTE_FORCE_IP');
```

2. **Behavioral Pattern Analysis**:
```javascript
// Catches credential stuffing (many users from one IP)
const uniqueUsers = await redis.scard(`ip:users:${ip}`);
if (uniqueUsers >= 20) triggerAlert('CREDENTIAL_STUFFING');

// Catches distributed attacks (many IPs targeting one user)
const uniqueIPs = await redis.scard(`user:ips:${username}`);
if (uniqueIPs >= 10) triggerAlert('DISTRIBUTED_ATTACK');
```

3. **Anomaly Detection**:
```javascript
// Catches account takeover via impossible travel
if (velocityKmH > 800) triggerAlert('IMPOSSIBLE_TRAVEL');

// Catches attack spikes via baseline comparison
if (current > baseline * 3) triggerAlert('GLOBAL_ANOMALY');
```

**Additional Protections**:
- **Alert cooldown**: Prevents alert fatigue by suppressing duplicate alerts within 15 minutes
- **Multi-channel alerting**: Slack for visibility, PagerDuty for critical incidents, SIEM for correlation
- **Privacy-preserving logging**: Usernames are hashed in stored events, only shown in alerts
- **Graceful degradation**: Alert failures are logged but don't break authentication flow
- **Time-series storage**: All events stored for 24 hours enabling forensic analysis and baseline calculation

Simply logging failed login attempts without alerting on suspicious patterns leaves your application blind to active attacks. Many breaches occur because security teams only discovered brute force attacks weeks later when reviewing logs.

**VULNERABLE CODE**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.*;
import java.sql.*;

public class AuthenticationService {
    private static final Logger logger = LoggerFactory.getLogger(AuthenticationService.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    public boolean authenticate(HttpServletRequest request, String username, String password) {
        String clientIp = request.getRemoteAddr();

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT password_hash FROM users WHERE username = ?");
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    logger.info("User {} logged in from {}", username, clientIp);
                    return true;
                } else {
                    // Just logging - no alerting!
                    logger.warn("Failed login for user {} from {}", username, clientIp);
                    return false;
                }
            }
            // Just logging non-existent user attempts
            logger.warn("Login attempt for non-existent user {} from {}", username, clientIp);
            return false;
        } catch (SQLException e) {
            logger.error("Database error during authentication", e);
            return false;
        }
    }
}
```

**Attack Scenario**:
```text
# Attacker runs brute force attack
for password in $(cat rockyou.txt); do
    curl -X POST https://app.example.com/login \
        -d "username=admin&password=$password"
done
# 10,000 attempts logged but no one is alerted
# By the time logs are reviewed, attacker has moved laterally
```

**Why This Is Dangerous**:
- Logs are written but never monitored in real-time
- No threshold-based alerting for brute force detection
- No correlation of patterns across multiple users/IPs
- Security team discovers attacks days or weeks later during log review
- Attackers can attempt thousands of passwords with no intervention

**SECURE VERSION**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.*;
import java.sql.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.time.Instant;
import java.time.Duration;

public class SecureAuthenticationService {
    private static final Logger logger = LoggerFactory.getLogger(SecureAuthenticationService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_EVENTS");

    private static final int FAILED_ATTEMPTS_THRESHOLD = 5;
    private static final int ALERT_THRESHOLD_MINUTES = 15;
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    private final ConcurrentHashMap<String, FailedAttemptTracker> failedAttempts = new ConcurrentHashMap<>();
    private final AlertingService alertingService;

    public SecureAuthenticationService(AlertingService alertingService) {
        this.alertingService = alertingService;
    }

    public boolean authenticate(HttpServletRequest request, String username, String password) {
        String clientIp = request.getRemoteAddr();
        String userAgent = request.getHeader("User-Agent");

        // Check if IP is already blocked
        if (isIpBlocked(clientIp)) {
            securityLogger.warn("BLOCKED_IP_ATTEMPT|ip={}|user={}|ua={}", 
                clientIp, username, userAgent);
            alertingService.sendAlert(AlertLevel.HIGH, 
                "Blocked IP attempted login: " + clientIp);
            return false;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            PreparedStatement stmt = conn.prepareStatement(
                "SELECT password_hash FROM users WHERE username = ?");
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    clearFailedAttempts(clientIp, username);
                    securityLogger.info("LOGIN_SUCCESS|ip={}|user={}|ua={}", 
                        clientIp, username, userAgent);
                    return true;
                }
            }

            // Track and alert on failed attempts
            handleFailedAttempt(clientIp, username, userAgent);
            return false;

        } catch (SQLException e) {
            logger.error("Database error during authentication", e);
            return false;
        }
    }

    private void handleFailedAttempt(String clientIp, String username, String userAgent) {
        FailedAttemptTracker tracker = failedAttempts.compute(clientIp, 
            (k, v) -> v == null ? new FailedAttemptTracker() : v);

        int attempts = tracker.incrementAndGet();

        securityLogger.warn("LOGIN_FAILED|ip={}|user={}|ua={}|attempts={}", 
            clientIp, username, userAgent, attempts);

        // Threshold-based alerting
        if (attempts == FAILED_ATTEMPTS_THRESHOLD) {
            alertingService.sendAlert(AlertLevel.MEDIUM, 
                String.format("Brute force detected: %d failed attempts from IP %s for user %s",
                    attempts, clientIp, username));
        } else if (attempts >= FAILED_ATTEMPTS_THRESHOLD * 2) {
            alertingService.sendAlert(AlertLevel.HIGH,
                String.format("CRITICAL: Ongoing brute force attack from IP %s (%d attempts)",
                    clientIp, attempts));
            blockIp(clientIp);
        }
    }

    private boolean isIpBlocked(String ip) {
        // Check against blocked IP list
        return false; // Implementation depends on your blocking mechanism
    }

    private void blockIp(String ip) {
        // Add to blocked list with TTL
        securityLogger.error("IP_BLOCKED|ip={}|reason=brute_force", ip);
    }

    private void clearFailedAttempts(String ip, String username) {
        failedAttempts.remove(ip);
    }
}

class FailedAttemptTracker {
    private final AtomicInteger count = new AtomicInteger(0);
    private volatile Instant firstAttempt = Instant.now();

    public int incrementAndGet() {
        return count.incrementAndGet();
    }
}
```

**Key Security Controls**:
