class AttemptMetrics {
    private final List<Instant> attempts = new CopyOnWriteArrayList<>();
    public int recentCount;
    public int windowMinutes = 15;

    public synchronized void recordAttempt() {
        Instant now = Instant.now();
        attempts.add(now);
        // Clean old entries and count recent
        Instant cutoff = now.minus(Duration.ofMinutes(windowMinutes));
        attempts.removeIf(t -> t.isBefore(cutoff));
        recentCount = attempts.size();
    }
}

