class SecurityMonitor {
  constructor(redis, alerter) {
    this.redis = redis;
    this.alerter = alerter;
    this.anomalyThresholds = {
      uniqueIPsPerUser: { count: 5, windowHours: 1 },
      uniqueUsersPerIP: { count: 20, windowHours: 1 },
      credentialStuffingScore: { score: 100, windowMinutes: 30 },
      geoVelocity: { maxKmPerHour: 1000 },
      failedUniqueUsers: { count: 50, windowMinutes: 10 }
    };
  }

  async analyzeLoginAttempt(context) {
    const anomalies = [];

    // Track unique IPs attempting this username
    const ipCount = await this.trackUniqueSet(
      `user:ips:${context.username}`,
      context.ip,
      3600
    );
    if (ipCount >= this.anomalyThresholds.uniqueIPsPerUser.count) {
      anomalies.push({
        type: 'distributed_attack_on_user',
        severity: 'HIGH',
        detail: `${ipCount} unique IPs targeting user ${context.username}`
      });
    }

    // Track unique usernames from this IP (credential stuffing indicator)
    const userCount = await this.trackUniqueSet(
      `ip:users:${context.ip}`,
      context.username,
      3600
    );
    if (userCount >= this.anomalyThresholds.uniqueUsersPerIP.count) {
      anomalies.push({
        type: 'credential_stuffing',
        severity: 'CRITICAL',
        detail: `IP ${context.ip} tested ${userCount} unique usernames`
      });
    }

    // Geo-velocity check for existing users
    if (context.userId) {
      const geoAnomaly = await this.checkGeoVelocity(context);
      if (geoAnomaly) anomalies.push(geoAnomaly);
    }

    // Behavioral fingerprint analysis
    const behaviorAnomaly = await this.analyzeBehavior(context);
    if (behaviorAnomaly) anomalies.push(behaviorAnomaly);

    // Calculate composite risk score
    const riskScore = await this.calculateRiskScore(context, anomalies);

    return { anomalies, riskScore };
  }

  async trackUniqueSet(key, value, expireSeconds) {
    await this.redis.sadd(key, value);
    await this.redis.expire(key, expireSeconds);
    return await this.redis.scard(key);
  }

  async checkGeoVelocity(context) {
    const lastLoginKey = `lastlogin:${context.userId}`;
    const lastLogin = await this.redis.hgetall(lastLoginKey);

    if (lastLogin.lat && lastLogin.lng) {
      const currentGeo = geoip.lookup(context.ip);
      if (currentGeo && currentGeo.ll) {
        const distance = this.calculateDistance(
          parseFloat(lastLogin.lat),
          parseFloat(lastLogin.lng),
          currentGeo.ll[0],
          currentGeo.ll[1]
        );

        const hoursSinceLastLogin = 
          (Date.now() - parseInt(lastLogin.timestamp)) / (1000 * 60 * 60);
        const velocity = distance / Math.max(hoursSinceLastLogin, 0.1);

        if (velocity > this.anomalyThresholds.geoVelocity.maxKmPerHour) {
          return {
            type: 'impossible_travel',
            severity: 'HIGH',
            detail: `Login from ${currentGeo.city}, ${currentGeo.country} ` +
                    `(${Math.round(velocity)} km/h from last location)`
          };
        }
      }
    }
    return null;
  }

  async analyzeBehavior(context) {
    const parser = new UAParser(context.userAgent);
    const browser = parser.getBrowser();
    const os = parser.getOS();
    const device = parser.getDevice();

    const fingerprint = `${browser.name}:${os.name}:${device.type || 'desktop'}`;

    if (context.userId) {
      const knownFingerprints = await this.redis.smembers(
        `user:fingerprints:${context.userId}`
      );

      if (knownFingerprints.length > 0 && 
          !knownFingerprints.includes(fingerprint)) {
        return {
          type: 'new_device',
          severity: 'MEDIUM',
          detail: `New device fingerprint: ${fingerprint}`
        };
      }
    }
    return null;
  }

  async calculateRiskScore(context, anomalies) {
    let score = 0;

    // Base score from anomalies
    for (const anomaly of anomalies) {
      switch (anomaly.severity) {
        case 'CRITICAL': score += 50; break;
        case 'HIGH': score += 30; break;
        case 'MEDIUM': score += 15; break;
        case 'LOW': score += 5; break;
      }
    }

    // Add score based on IP reputation
    const ipFailures = await this.redis.get(`failures:ip:${context.ip}`) || 0;
    score += Math.min(parseInt(ipFailures) * 2, 30);

    // Time-based risk (attacks often happen outside business hours)
    const hour = new Date().getHours();
    if (hour < 6 || hour > 22) score += 10;

    // Store and check trend
    await this.redis.zadd(
      'global:risk:timeline',
      Date.now(),
      `${Date.now()}:${score}`
    );

    return score;
  }

  calculateDistance(lat1, lon1, lat2, lon2) {
    const R = 6371; // Earth's radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  }
}

class AlertManager {
  constructor(slack, logger) {
    this.slack = slack;
    this.logger = logger;
    this.alertCooldowns = new Map();
  }

  async sendAlert(alertType, severity, details) {
    // Prevent alert fatigue with cooldowns
    const cooldownKey = `${alertType}:${details.identifier || 'global'}`;
    const lastAlert = this.alertCooldowns.get(cooldownKey);
    const cooldownMinutes = severity === 'CRITICAL' ? 1 : 5;

    if (lastAlert && Date.now() - lastAlert < cooldownMinutes * 60 * 1000) {
      return; // Skip duplicate alert
    }
    this.alertCooldowns.set(cooldownKey, Date.now());

    const alertPayload = {
      alertId: `ALERT-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      alertType,
      severity,
      timestamp: new Date().toISOString(),
      details,
      requiresAck: severity === 'CRITICAL'
    };

    // Log for SIEM
    this.logger.warn('SECURITY_ALERT', alertPayload);

    // Slack notification
    const emoji = severity === 'CRITICAL' ? ':rotating_light:' : ':warning:';
    await this.slack.chat.postMessage({
      channel: process.env.SECURITY_CHANNEL,
      text: `${emoji} ${severity} Alert: ${alertType}`,
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: `${emoji} ${alertType}` }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: `*Severity:*\n${severity}` },
            { type: 'mrkdwn', text: `*Alert ID:*\n${alertPayload.alertId}` },
            { type: 'mrkdwn', text: `*Details:*\n${JSON.stringify(details, null, 2)}` }
          ]
        },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: { type: 'plain_text', text: 'Acknowledge' },
              style: 'danger',
              action_id: `ack_${alertPayload.alertId}`
            },
            {
              type: 'button',
              text: { type: 'plain_text', text: 'View Dashboard' },
              url: `${process.env.DASHBOARD_URL}/alerts/${alertPayload.alertId}`
            }
          ]
        }
      ]
    });

    // PagerDuty for critical alerts
    if (severity === 'CRITICAL') {
      await this.triggerPagerDuty(alertPayload);
    }
  }

  async triggerPagerDuty(alert) {
    // PagerDuty integration for critical alerts
    const fetch = require('node-fetch');
    await fetch('https://events.pagerduty.com/v2/enqueue', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        routing_key: process.env.PAGERDUTY_KEY,
        event_action: 'trigger',
        dedup_key: alert.alertId,
        payload: {
          summary: `${alert.alertType}: ${JSON.stringify(alert.details)}`,
          severity: 'critical',
          source: 'auth-service'
        }
      })
    });
  }
}

