```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.sql.*;
import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import javax.servlet.http.*;

public class AuthenticationService {
    private static final Logger logger = LoggerFactory.getLogger(AuthenticationService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // Threshold-based alerting
    private static final int ALERT_THRESHOLD_PER_USER = 5;
    private static final int ALERT_THRESHOLD_PER_IP = 10;
    private static final long WINDOW_MILLIS = 300000; // 5 minutes

    private final ConcurrentHashMap<String, FailureTracker> userFailures = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, FailureTracker> ipFailures = new ConcurrentHashMap<>();
    private final AlertService alertService;

    public AuthenticationService(AlertService alertService) {
        this.alertService = alertService;
    }

    public boolean authenticate(HttpServletRequest request, String username, String password) {
        String clientIp = getClientIp(request);
        String userAgent = request.getHeader("User-Agent");
        String sessionId = request.getSession().getId();

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    handleSuccessfulLogin(username, clientIp, userAgent, sessionId);
                    return true;
                }
            }

            handleFailedLogin(username, clientIp, userAgent, sessionId);
            return false;
        } catch (SQLException e) {
            securityLogger.error("Database error during auth - ip={} user={}", clientIp, username, e);
            return false;
        }
    }

    private void handleFailedLogin(String username, String ip, String userAgent, String sessionId) {
        // Structured security logging
        securityLogger.warn("AUTH_FAILURE event=failed_login user={} ip={} userAgent={} sessionId={} timestamp={}",
            username, ip, userAgent, sessionId, Instant.now());

        // Track and check thresholds
        int userFailCount = trackFailure(userFailures, username);
        int ipFailCount = trackFailure(ipFailures, ip);

        // CRITICAL: Alert on suspicious patterns
        if (userFailCount >= ALERT_THRESHOLD_PER_USER) {
            triggerAlert("BRUTE_FORCE_USER", username, ip, userFailCount);
        }

        if (ipFailCount >= ALERT_THRESHOLD_PER_IP) {
            triggerAlert("BRUTE_FORCE_IP", username, ip, ipFailCount);
        }
    }

    private void triggerAlert(String alertType, String username, String ip, int failCount) {
        securityLogger.error("SECURITY_ALERT type={} user={} ip={} failCount={} window=5min",
            alertType, username, ip, failCount);

        // Send real-time alert to security team
        alertService.sendCriticalAlert(
            alertType,
            String.format("Suspicious auth activity: %d failures for %s from %s", 
                failCount, username, ip),
            ip,
            username
        );
    }

    private int trackFailure(ConcurrentHashMap<String, FailureTracker> map, String key) {
        return map.compute(key, (k, tracker) -> {
            if (tracker == null || tracker.isExpired(WINDOW_MILLIS)) {
                return new FailureTracker();
            }
            tracker.increment();
            return tracker;
        }).getCount();
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
