    private static final int BASE_IP_THRESHOLD = 10;
    private static final int GLOBAL_FAILURE_RATE_THRESHOLD = 100; // per minute across all users
    private static final double ANOMALY_SCORE_THRESHOLD = 0.85;

    public AdvancedSecurityMonitor(MeterRegistry metrics, AlertService alertService, 
