        scheduler.scheduleAtFixedRate(this::analyzeGlobalPatterns, 1, 1, TimeUnit.MINUTES);
        scheduler.scheduleAtFixedRate(this::detectSlowAttacks, 5, 5, TimeUnit.MINUTES);
