    public SecurityDecision evaluateAuthAttempt(HttpServletRequest request, 
                                                 String username, boolean success) {
        String clientIp = extractClientIp(request);
        String userAgent = request.getHeader("User-Agent");
        String geoLocation = threatIntel.getGeoLocation(clientIp);
        Instant timestamp = Instant.now();

        // Build comprehensive auth event
        AuthEvent event = AuthEvent.builder()
            .username(username)
            .clientIp(clientIp)
            .userAgent(userAgent)
            .geoLocation(geoLocation)
            .success(success)
            .timestamp(timestamp)
            .requestFingerprint(generateFingerprint(request))
            .build();

        globalEventBuffer.add(event);

        // Multi-layer analysis
        double threatScore = calculateThreatScore(event);
        List<ThreatIndicator> indicators = new ArrayList<>();

        // Layer 1: Known bad actors
        if (threatIntel.isKnownMaliciousIP(clientIp)) {
            indicators.add(ThreatIndicator.KNOWN_BAD_IP);
            threatScore += 0.4;
        }

        // Layer 2: Impossible travel detection
        UserBehaviorProfile profile = userProfiles.get(username);
        if (profile != null && profile.isImpossibleTravel(geoLocation, timestamp)) {
            indicators.add(ThreatIndicator.IMPOSSIBLE_TRAVEL);
            threatScore += 0.3;
            triggerImmediateAlert("IMPOSSIBLE_TRAVEL", event, 
                "User authenticated from " + profile.getLastLocation() + 
                " and " + geoLocation + " within " + 
                Duration.between(profile.getLastAuthTime(), timestamp).toMinutes() + " minutes");
        }

        // Layer 3: Credential stuffing detection (many users, same IP)
        long uniqueUsersFromIP = globalEventBuffer.stream()
            .filter(e -> e.getClientIp().equals(clientIp))
            .filter(e -> !e.isSuccess())
            .filter(e -> e.getTimestamp().isAfter(timestamp.minus(Duration.ofMinutes(5))))
            .map(AuthEvent::getUsername)
            .distinct()
            .count();

        if (uniqueUsersFromIP > 20) {
            indicators.add(ThreatIndicator.CREDENTIAL_STUFFING);
            threatScore += 0.5;
            triggerImmediateAlert("CREDENTIAL_STUFFING", event,
                "IP " + clientIp + " attempted " + uniqueUsersFromIP + " unique accounts in 5 minutes");
        }

        // Layer 4: Behavioral anomaly (unusual time, device, location)
        if (profile != null) {
            double anomalyScore = profile.calculateAnomalyScore(event);
            if (anomalyScore > ANOMALY_SCORE_THRESHOLD) {
                indicators.add(ThreatIndicator.BEHAVIORAL_ANOMALY);
                threatScore += anomalyScore * 0.3;
            }
        }

        // Layer 5: Velocity checks with adaptive thresholds
        IPReputationScore ipScore = ipScores.computeIfAbsent(clientIp, 
            k -> new IPReputationScore());
        int adaptiveThreshold = calculateAdaptiveThreshold(ipScore);

        if (!success) {
            int recentFailures = ipScore.recordFailure();
            if (recentFailures >= adaptiveThreshold) {
                indicators.add(ThreatIndicator.VELOCITY_EXCEEDED);
                threatScore += 0.2;
            }
