        logSecurityEvent(event, threatScore, indicators);

        // Update metrics for dashboards
        metrics.counter("auth.attempts", 
            "success", String.valueOf(success),
            "threat_level", categorizeThreat(threatScore)).increment();

        // Make security decision
        return SecurityDecision.builder()
            .allow(threatScore < 0.7)
            .requireMFA(threatScore >= 0.5 && threatScore < 0.7)
            .block(threatScore >= 0.7)
            .threatScore(threatScore)
            .indicators(indicators)
            .build();
    }

    private void analyzeGlobalPatterns() {
        Instant windowStart = Instant.now().minus(Duration.ofMinutes(1));

        long totalFailures = globalEventBuffer.stream()
            .filter(e -> e.getTimestamp().isAfter(windowStart))
            .filter(e -> !e.isSuccess())
            .count();

        // Detect coordinated attack (spike in global failures)
        if (totalFailures > GLOBAL_FAILURE_RATE_THRESHOLD) {
            Map<String, Long> failuresByIP = globalEventBuffer.stream()
                .filter(e -> e.getTimestamp().isAfter(windowStart))
                .filter(e -> !e.isSuccess())
                .collect(Collectors.groupingBy(AuthEvent::getClientIp, Collectors.counting()));

            securityLogger.error("SECURITY_ALERT type=COORDINATED_ATTACK " +
                "totalFailures={} uniqueIPs={} topAttackers={}",
                totalFailures, failuresByIP.size(), getTopN(failuresByIP, 5));

            alertService.sendCriticalAlert(
                "COORDINATED_ATTACK",
                String.format("Global auth failure spike: %d failures in 1 minute from %d IPs",
                    totalFailures, failuresByIP.size()),
                AlertSeverity.CRITICAL,
                true // Page on-call
            );
        }

        metrics.gauge("auth.global_failure_rate", totalFailures);
    }

    private void detectSlowAttacks() {
        Instant windowStart = Instant.now().minus(Duration.ofHours(24));

        // Detect low-and-slow attacks staying under per-minute thresholds
        Map<String, List<AuthEvent>> eventsByIP = globalEventBuffer.stream()
            .filter(e -> e.getTimestamp().isAfter(windowStart))
            .filter(e -> !e.isSuccess())
            .collect(Collectors.groupingBy(AuthEvent::getClientIp));

        for (Map.Entry<String, List<AuthEvent>> entry : eventsByIP.entrySet()) {
            String ip = entry.getKey();
            List<AuthEvent> events = entry.getValue();

            if (events.size() > 50) { // 50+ failures over 24h is suspicious
                long uniqueUsers = events.stream()
                    .map(AuthEvent::getUsername)
                    .distinct()
                    .count();

                // Check if it's distributed across many users (credential stuffing)
                // vs targeting one user (targeted attack)
                String attackType = uniqueUsers > 10 ? 
                    "SLOW_CREDENTIAL_STUFFING" : "SLOW_TARGETED_ATTACK";

                securityLogger.warn("SECURITY_ALERT type={} ip={} failures24h={} uniqueUsers={}",
                    attackType, ip, events.size(), uniqueUsers);

                alertService.sendAlert(
                    attackType,
                    String.format("Slow attack detected from %s: %d failures against %d users over 24h",
                        ip, events.size(), uniqueUsers),
                    AlertSeverity.HIGH
                );
            }
        }
    }

    private void triggerImmediateAlert(String alertType, AuthEvent event, String details) {
        securityLogger.error("IMMEDIATE_ALERT type={} user={} ip={} details={}",
            alertType, event.getUsername(), event.getClientIp(), details);

        alertService.sendCriticalAlert(
            alertType,
            details,
            AlertSeverity.CRITICAL,
            true // Immediate page
        );

        // Emit event for SIEM/SOAR integration
        metrics.counter("security.alerts", "type", alertType).increment();
    }

    private void logSecurityEvent(AuthEvent event, double threatScore, 
                                   List<ThreatIndicator> indicators) {
        // Structured JSON logging for SIEM ingestion
        securityLogger.info("AUTH_EVENT " +
            "timestamp={} " +
            "event_type={} " +
            "username={} " +
            "client_ip={} " +
            "geo_location={} " +
            "user_agent={} " +
            "success={} " +
            "threat_score={} " +
            "indicators={} " +
            "fingerprint={}",
            event.getTimestamp(),
            "authentication",
            event.getUsername(),
            event.getClientIp(),
            event.getGeoLocation(),
            event.getUserAgent(),
            event.isSuccess(),
            String.format("%.2f", threatScore),
            indicators,
            event.getRequestFingerprint());
    }

    private int calculateAdaptiveThreshold(IPReputationScore ipScore) {
        // Lower threshold for IPs with bad history
        if (ipScore.getReputationScore() < 0.3) {
            return BASE_IP_THRESHOLD / 2;
        }
        return BASE_IP_THRESHOLD;
    }

    private String extractClientIp(HttpServletRequest request) {
        // Handle proxies/load balancers
        for (String header : Arrays.asList("X-Forwarded-For", "X-Real-IP", "CF-Connecting-IP")) {
            String value = request.getHeader(header);
            if (value != null && !value.isEmpty()) {
                return value.split(",")[0].trim();
            }
        }
        return request.getRemoteAddr();
    }
